CREATE OR REPLACE FUNCTION fpa_gos_c_by_mem (ai_year bigint,ai_month bigint,as_kep char,as_pcode char) RETURNS bigint AS $body$
DECLARE

    ldc_count integer;

BEGIN
  select count(1)  into STRICT ldc_count
  from sc_kep_t_monthly_receive
      ,sc_mem_m_ucf_member_group
      ,sc_mem_m_ucf_province
  where (sc_kep_t_monthly_receive.member_group_no = sc_mem_m_ucf_member_group.member_group_no)
  and (sc_mem_m_ucf_member_group.province_code = sc_mem_m_ucf_province.province_code)
  and sc_kep_t_monthly_receive.kep_method_amount > 0
  and sc_kep_t_monthly_receive.receive_year = ai_year
  and sc_kep_t_monthly_receive.receive_month = ai_month
  and sc_kep_t_monthly_receive.kep_method = as_kep
  and sc_mem_m_ucf_province.province_code = as_pcode
  group by sc_mem_m_ucf_province.province_code
  order by sc_mem_m_ucf_province.province_code;

  return ldc_count;

exception
when no_data_found then return null;
when too_many_rows then return null;
when others then CALL spa_dberror('fpa_gos_c_by_mem');
end;
$body$
LANGUAGE PLPGSQL
